<script setup>import{computed,ref}from"vue";import{onShow}from"@dcloudio/uni-app";import{api,showError}from"../../services/api";import{persistSession,requireLogin,session}from"../../services/session";const members=ref([]),name=ref(''),type=ref('personal'),email=ref(''),displayName=ref(''),busy=ref(false);const active=computed(()=>session.ledgers.find(x=>x.id===session.activeLedgerId));const typeLabel=v=>({personal:'个人账本',family:'家庭账本',shared:'共享账本'}[v]||v);async function load(){if(!requireLogin())return;try{session.ledgers=await api.ledgers();members.value=active.value?await api.members(active.value.id):[]}catch(e){showError(e)}}async function choose(x){session.activeLedgerId=x.id;persistSession();await load();uni.showToast({title:`已切换到${x.name}`,icon:'none'})}async function create(){if(!name.value.trim())return;busy.value=true;try{const x=await api.createLedger(name.value.trim(),type.value);session.ledgers.push(x);name.value='';await choose(x)}catch(e){showError(e)}finally{busy.value=false}}async function add(){if(!email.value.trim())return;busy.value=true;try{await api.addMember(active.value.id,email.value.trim(),displayName.value.trim());email.value=displayName.value='';await load()}catch(e){showError(e)}finally{busy.value=false}}onShow(load);</script>
<template><view class="page"><view class="hero"><text class="eyebrow">用户与账本</text><text class="title">管理账户和账本</text><text class="subtle">{{session.user?.display_name}} · {{session.user?.email}}</text></view><view class="card"><view class="card-title"><text>我的账本</text><text class="muted">{{session.ledgers.length}} 个</text></view><view v-for="x in session.ledgers" :key="x.id" :class="['ledger-row',{active:x.id===session.activeLedgerId}]" @click="choose(x)"><view><text>{{x.name}}</text><text class="muted">{{typeLabel(x.type)}} · {{x.member_count}} 人</text></view><text class="pill">{{x.role}}</text></view><label class="field top">新账本名称<input v-model="name" class="input" placeholder="例如：家庭账本"/></label><label class="field">账本类型<picker :range="['个人账本','家庭账本','共享账本']" @change="type=['personal','family','shared'][$event.detail.value]"><view class="picker">{{typeLabel(type)}}</view></picker></label><button class="btn primary" :disabled="busy||!name.trim()" @click="create">创建账本</button></view><view class="card"><view class="card-title"><text>账本成员</text><text class="muted">{{active?.name}}</text></view><view v-for="x in members" :key="x.id" class="member"><view><text>{{x.display_name}}</text><text class="muted">{{x.email}}</text></view><text class="pill">{{x.role}}</text></view><view v-if="!members.length" class="empty">暂无成员</view><label class="field top">成员邮箱<input v-model="email" class="input"/></label><label class="field">显示名称（可选）<input v-model="displayName" class="input"/></label><button class="btn primary" :disabled="busy||!active||!email.trim()" @click="add">添加成员</button></view></view></template>
<style scoped>.ledger-row,.member{display:flex;align-items:center;justify-content:space-between;padding:22rpx;border-bottom:1rpx solid #eee7dc}.ledger-row view text,.member view text{display:block}.ledger-row.active{margin:5rpx 0;background:#fff0e5;border-radius:18rpx;color:#b65e40;border:0}.top{margin-top:28rpx}.btn{width:100%}</style>



